function validateVerb(verb) {
  if (typeof verb !== 'string' || !/^[a-z][a-z0-9_-]*$/.test(verb)) {
    throw new Error(`invalid verb '${verb}'; expected a kebab/snake-case identifier`);
  }
  return verb;
}

